custom_css:
/* 🌊 Deep Dive 🤿*/

/*  — FONTS — */
@import url('https://fonts.googleapis.com/css2?family=Varela+Round&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Fredoka:wght@600&display=swap');

:root {
  --white30a: rgba(38, 168, 168, 0.8);
  --white50a: rgba(80, 200, 192, 0.9);
}

body, .mes_text, textarea, input, select, button {
  font-family: 'Varela Round', sans-serif !important;
}

/*  — BACKGROUND — */
#sheld {
  background-color: #040d14 !important;
}

/*  — CHAT AREA — */
#chat {
  padding: 16px 16px !important;
  border-top: 2px solid transparent !important;
  border-image: linear-gradient(to right,
    rgba(72, 56, 120, 0.7),
    rgba(38, 168, 168, 0.9),
    rgba(56, 180, 212, 0.8),
    rgba(38, 168, 168, 0.9),
    rgba(72, 56, 120, 0.7)
  ) 1 !important;
  margin-top: 0px !important;
  margin-bottom: -1px !important;
  background-image: radial-gradient(circle, rgba(38, 168, 168, 0.07) 1px, transparent 1px) !important;
  background-size: 8px 8px !important;
  min-height: 250px !important;
}

/*  — MESSAGE BUBBLES — */
.mes {
  position: relative !important;
  border-radius: 20px !important;
  padding: 14px 0px 16px 10px !important;
  margin-bottom: 14px !important;
  border: 3px solid rgba(38, 168, 168, 0.15) !important;
  box-shadow:
    0 4px 20px rgba(0, 0, 0, 0.6),
    inset 0 1px 0 rgba(38, 168, 168, 0.06) !important;
}

/* Character bubble */
.mes[is_user="false"] {
  padding-left: 70px !important;
  position: relative !important;
  background: linear-gradient(
    to bottom,
    rgba(6, 18, 32, 0.0) 0px,
    rgba(6, 18, 32, 0.0) 0px,
    rgba(6, 18, 32, 0.97) 0px,
    rgba(8, 22, 36, 0.97) 100%
  ) !important;
  border-color: rgba(38, 168, 168, 0.4) !important;
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.65),
    0 0 18px rgba(38, 168, 168, 0.06),
    inset 0 1px 0 rgba(38, 168, 168, 0.08) !important;
}
.mes[is_user="false"] .mesAvatarWrapper {
  position: absolute !important;
  top: 12px !important;
  left: 12px !important;
  right: auto !important;
}
.mes[is_user="false"] .mes_block {
  margin-left: 0 !important;
  margin-right: 0 !important;
}

/* User bubble */
.mes[is_user="true"] {
  padding-right: 54px !important;
  position: relative !important;
  flex-direction: row-reverse;
  margin-left: auto;
  background: linear-gradient(
    to bottom,
    rgba(6, 14, 24, 0.0) 0px,
    rgba(6, 14, 24, 0.0) 0px,
    rgba(6, 14, 24, 0.97) 0px,
    rgba(8, 18, 30, 0.97) 100%
  ) !important;
  border-color: rgba(48, 108, 188, 0.45) !important;
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.65),
    0 0 18px rgba(48, 108, 188, 0.06),
    inset 0 1px 0 rgba(48, 108, 188, 0.08) !important;
}
.mes[is_user="true"] .mesAvatarWrapper {
  position: absolute !important;
  top: 12px !important;
  right: 12px !important;
  left: auto !important;
}
.mes[is_user="true"] .mes_block {
  margin-left: 0 !important;
  margin-right: 0 !important;
}

/* User name header flex fixes */
.mes[is_user="true"] .mes_block .ch_name.flex-container.justifySpaceBetween {
  flex-direction: row-reverse;
  margin-left: auto;
}
.mes[is_user="true"] .mes_block .ch_name.flex-container.justifySpaceBetween .flex-container.flex1.alignitemscenter {
  flex-direction: row-reverse;
}
.mes[is_user="true"] .mes_block .ch_name.flex-container.justifySpaceBetween .flex-container.flex1.alignitemscenter .flex-container.alignItemsBaseline {
  flex-direction: row-reverse;
}

/*  — MESSAGE TEXT — */
.mes_text,
.mes_text p,
.mes_text em,
.mes_text strong {
  text-align: justify !important;
  text-shadow: none !important;
  color: #c8e8e4 !important;
  line-height: 1.8 !important;
  letter-spacing: 0.01em !important;
}

/* Character text */
.mes[is_user="false"] .mes_text q,
.mes[is_user="false"] .mes_text blockquote { color: rgba(80, 200, 192, 1) !important; }
.mes[is_user="false"] .mes_text em         { color: rgba(56, 200, 136, 1) !important; }
.mes[is_user="false"] .mes_text strong em,
.mes[is_user="false"] .mes_text em strong  { color: rgba(96, 212, 200, 1) !important; }
.mes[is_user="false"] .mes_text u          { color: rgba(38, 168, 168, 1) !important; }

/* User text */
.mes[is_user="true"] .mes_text q,
.mes[is_user="true"] .mes_text blockquote  { color: rgba(80, 148, 228, .9) !important; }
.mes[is_user="true"] .mes_text em          { color: rgba(100, 180, 220, .8) !important; }
.mes[is_user="true"] .mes_text strong em,
.mes[is_user="true"] .mes_text em strong   { color: rgba(130, 200, 240, .9) !important; }
.mes[is_user="true"] .mes_text u           { color: rgba(80, 148, 228, .8) !important; }

/*  — NAMES — */
.ch_name .name_text {
  display: none !important;
}

/* Character name */
.mes::after {
  font-family: 'Fredoka', sans-serif !important;
  content: '< ' attr(ch_name) ' >' !important;
  position: absolute !important;
  top: 14px !important;
  left: 80px !important;
  font-size: 1.4em !important;
  line-height: 1 !important;
  color: rgba(48, 83, 130, 1) !important;
  z-index: 10 !important;
  white-space: nowrap !important;
}

/* User name */
.mes[is_user="true"]::after {
  content: '< ' attr(ch_name) ' >' !important;
  left: auto !important;
  right: 80px !important;
  text-align: right !important;
  color: rgba(57, 172, 142, 1) !important;
}

/*  — AVATARS — */
/* Character avatar */
.mes[is_user="false"] .avatar,
.mes[is_user="false"] .avatar img {
  box-shadow: 0 0 0 3px rgba(48, 83, 130, 1) !important;
  animation: none !important;
}

/* User avatar */
.mes[is_user="true"] .avatar,
.mes[is_user="true"] .avatar img {
  box-shadow: 0 0 0 3px rgba(57, 172, 142, 1) !important;
  animation: none !important;
}

/* Everything else */
.mes .avatar,
.avatar img {
  box-shadow: 0 0 0 3px rgba(47, 185, 149, 1) !important;
  animation: none !important;
}

/*  — TIMESTAMPS & METADATA — */
.mes[is_user="false"] .timestamp {
  margin-top: 20px !important;
  margin-left: 0px;
  color: rgba(56, 180, 212, 1) !important;
  display: block !important;
  text-align: left !important;
}
.mes[is_user="true"] .timestamp {
  margin-top: 20px !important;
  margin-right: 26px;
  color: rgba(38, 168, 168, 1) !important;
  display: block !important;
  text-align: right !important;
}
.mes .mesIDDisplay,
.mes .mes_timer,
.mes .tokenCounterDisplay {
  margin-top: 10px;
  color: rgba(122, 170, 164, 0.55) !important;
}
.mes .mesIDDisplay { margin-bottom: -10px; }
.mes .mes_timer { margin-bottom: -10px; }
.mes .tokenCounterDisplay {
  position: relative !important;
  top: 0px !important;
}

/*  — MARKDOWN ELEMENTS — */
/* UI headers outside chat */
h1, h2, h3, h4, .standoutHeader {
  background: linear-gradient(90deg,
    rgba(6, 18, 32, 0.98),
    rgba(8, 24, 42, 0.98),
    rgba(6, 18, 32, 0.98)
  ) !important;
  color: #50c8c0 !important;
  border-radius: 8px !important;
  border-top: 1px solid rgba(38, 168, 168, 0.3) !important;
  border-bottom: 1px solid rgba(38, 168, 168, 0.3) !important;
}

/* All headers in chat */
.mes_text h1,
.mes_text h2,
.mes_text h3,
.mes_text h4 {
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  gap: 12px !important;
  margin: 8px auto !important;
  padding: 6px 20px !important;
  clip-path: none !important;
  color: #50c8c0 !important;
  border-radius: 50% 50% 48% 52% / 8% 8% 8% 8% !important;
  border-top: 2px solid rgba(38, 168, 168, 0.3) !important;
  border-bottom: 2px solid rgba(38, 168, 168, 0.3) !important;
  box-shadow: inset 0 0 14px rgba(38, 168, 168, 0.15) !important;
}

/* Sizes and widths */
.mes_text h1 { font-size: 1.5em !important; width: 40% !important; }
.mes_text h2 { font-size: 1.0em !important; width: 100% !important; }
.mes_text h3 { font-size: 1.1em !important; width: 40% !important; }
.mes_text h4 { font-size: 0.9em !important; width: 40% !important; }

/* Character bubble headers */
.mes[is_user="false"] .mes_text h1,
.mes[is_user="false"] .mes_text h2,
.mes[is_user="false"] .mes_text h3,
.mes[is_user="false"] .mes_text h4 {
  background: linear-gradient(90deg,
    rgba(6, 18, 32, 0.98),
    rgba(8, 24, 42, 0.98),
    rgba(6, 18, 32, 0.98)
  ) !important;
}

/* User bubble headers */
.mes[is_user="true"] .mes_text h1,
.mes[is_user="true"] .mes_text h2,
.mes[is_user="true"] .mes_text h3,
.mes[is_user="true"] .mes_text h4 {
  background: linear-gradient(90deg,
    rgba(6, 14, 24, 0.98),
    rgba(8, 20, 36, 0.98),
    rgba(6, 14, 24, 0.98)
  ) !important;
}

/* Horizontal rule */
.mes_text hr {
  border: none !important;
  height: 3px !important;
  background: linear-gradient(to right,
    transparent,
    rgba(72, 56, 120, 0.7),
    rgba(38, 168, 168, 0.9),
    rgba(56, 200, 136, 0.8),
    rgba(56, 180, 212, 0.7),
    transparent
  ) !important;
  margin: 12px auto !important;
  width: 80% !important;
}

/*  — BUTTONS & ICONS — */
.mes_buttons, .extraMesButtons {
  box-shadow: none !important;
 margin-right: 20px !important;
  text-shadow: none !important;
}
.mes_edit_buttons {
  filter: none !important;
  margin-right: 30px !important;
}
.mes_buttons button, .mes_buttons .fa-solid, .mes_buttons i {
  box-shadow: none !important;
  text-shadow: none !important;
  filter: none !important;
  color: rgba(38, 168, 168, 1) !important;
}
.mes_edit_buttons button {
  opacity: 1 !important;
  filter: none !important;
  background-color: rgba(6, 18, 32, 0.92) !important;
  border: 1px solid rgba(38, 168, 168, 0.35) !important;
  color: #c8e8e4 !important;
}
.mes_edit_buttons { filter: drop-shadow(0px 0px 0px transparent); }
.fa-solid { text-shadow: none !important; filter: none !important; box-shadow: none !important; }

.mes.smallSysMes::after { display: none !important; }

.mes.smallSysMes { padding-left: 0px !important; }

div.custom-flex-container {
  display: flex !important;
  justify-content: center !important;
  margin-left: 0 !important;
}

/*  — INPUT AREA — */
#form_sheld {
  padding: 4px 0.5% 0 !important;
  border-top: 2px solid transparent !important;
  border-image: linear-gradient(to right,
    rgba(72, 56, 120, 0.7),
    rgba(38, 168, 168, 0.9),
    rgba(56, 180, 212, 0.8),
    rgba(38, 168, 168, 0.9),
    rgba(72, 56, 120, 0.7)
  ) 1 !important;
  background: #040d14 !important;
  background-color: #040d14 !important;
}
#send_form {
  border: 1.5px solid rgba(38, 168, 168, 0.28) !important;
  border-radius: 20px !important;
  background: rgba(6, 18, 32, 0.97) !important;
  box-shadow: 0 2px 14px rgba(0, 0, 0, 0.5) !important;
}
#send_form:focus-within {
  border-color: rgba(38, 168, 168, 0.8) !important;
  box-shadow: 0 0 0 3px rgba(38, 168, 168, 0.12), 0 2px 14px rgba(0, 0, 0, 0.5) !important;
}
#send_textarea {
  min-height: 20px;
  color: #c8e8e4 !important;
  font-size: 16px !important;
}
select, .form-control, .ui-widget-content {
  background-color: rgba(8, 22, 38, 0.9) !important;
  color: #c8e8e4 !important;
  border: 1px solid rgba(38, 168, 168, 0.28) !important;
}
input[type="text"], input[type="search"], input[type="number"],
textarea, .form-control {
  background-color: rgba(6, 18, 32, 0.95) !important;
  color: #c8e8e4 !important;
  border: 1px solid rgba(38, 168, 168, 0.28) !important;
}

/*  — TOP BAR — */
#top-bar {
  height: var(--topBarBlockSize) !important;
  display: flex !important;
  flex-wrap: wrap !important;
  align-items: center !important;
  overflow: visible !important;
  box-shadow: none !important;
  border: none !important;
  margin-bottom: 0 !important;
  padding-bottom: 4px !important;
  background: linear-gradient(90deg,
    rgba(4, 10, 20, 0.99),
    rgba(6, 14, 26, 0.99)
  ) !important;
}

/*  — SCROLLBAR — */
::-webkit-scrollbar { width: 8px; background: rgba(4, 10, 20, 0.95); }
::-webkit-scrollbar-thumb {
  background: linear-gradient(to bottom,
    rgba(38, 168, 168, 0.85) 0%,
    rgba(56, 180, 212, 0.85) 50%,
    rgba(56, 200, 136, 0.85) 100%
  );
  border: 2px solid rgba(6, 18, 32, 0.8);
  border-radius: 8px;
}
::-webkit-scrollbar-thumb:hover {
  background: linear-gradient(to bottom,
    rgba(80, 200, 192, 1) 0%,
    rgba(80, 200, 240, 1) 50%,
    rgba(80, 220, 160, 1) 100%
  );
}

/*  — DROPDOWNS & FORM ELEMENTS — */
.select2-container .select2-selection {
  background-color: rgba(8, 22, 38, 0.9) !important;
  color: #c8e8e4 !important;
  border: 1px solid rgba(38, 168, 168, 0.28) !important;
}
.select2-container .select2-selection__rendered { color: #c8e8e4 !important; }
.select2-dropdown {
  background-color: rgba(6, 18, 32, 0.97) !important;
  border: 1px solid rgba(38, 168, 168, 0.28) !important;
}

/*  — PROMPT MANAGER — */
#completion_prompt_manager_list { background-color: rgba(6, 18, 32, 0.8) !important; }
.completion_prompt_manager_header span { color: #c8e8e4 !important; text-shadow: none !important; filter: none !important; }
.completion_prompt_manager_header * { font-weight: bold !important; }
.completion_prompt_manager_prompt_disabled * {
  color: rgba(122, 170, 164, 0.45) !important;
  opacity: 1 !important;
}

/*  — PANELS & EXTENSIONS — */
#options { z-index: 5000 !important; }
#floatingPrompt, #cfgConfig, #SnippetsExtensionWindow, #WorldInfo {
  z-index: 4999 !important;
  max-width: 80vw !important;
  background: rgba(4, 12, 22, 0.99) !important;
  border: 1.5px solid rgba(38, 168, 168, 0.32) !important;
}
.drawer-content { margin-top: 0px !important; }
.floating_panel { max-width: 90vw !important; }
#WorldInfo { max-width: 85vw !important; max-height: 90vh !important; }
.world_entry .world_entry_form_control { width: 100% !important; }
#extensions_settings,
#extensions_settings2 {
  max-width: 90vw !important;
  background: rgba(4, 12, 22, 0.99) !important;
  color: #c8e8e4 !important;
}
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header {
  background: linear-gradient(90deg,
    rgba(6, 18, 32, 0.98),
    rgba(8, 24, 42, 0.98),
    rgba(6, 18, 32, 0.98)
  ) !important;
  color: #50c8c0 !important;
  border-radius: 8px !important;
}

/*  — SELECTION — */
::selection {
  background: rgba(38, 168, 168, 0.28) !important;
  color: #e0f4f0 !important;
}
